unitsize(1 cm);

pair B, C, D, E;

B = (0,0);
C = (2,0);
D = (7,3);
E = (8,4);

draw((-1.5,0.5)--(6,0.5),dashed);
draw((-1.5,-0.5)--(6,-0.5),dashed);
draw((2,2 - 4 + 0.5)--(8,8 - 4 + 0.5),dashed);
draw((3,3 - 4 - 0.5)--(9,9 - 4 - 0.5),dashed);

dot("$B$", B, W);
dot("$C$", C, dir(0));
dot("$D$", D, SW);
dot("$E$", E, NE);
dot(extension((-1.5,0.5),(6,0.5),(2,2 - 4 + 0.5),(8,8 - 4 + 0.5)),red);
